Action.Str:
var expectedToken = global('TAILCLIP_TOKEN') || '';
var headersRaw = tailclip_headers || '';
var bodyRaw = tailclip_body || '';
var tailclip_status = '401';
var tailclip_content = '';

function escapeRegex(s) {
    return String(s).replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
}

headersRaw = String(headersRaw);
bodyRaw = String(bodyRaw);

if (expectedToken) {
    var authRegex = new RegExp('(^|,|\\n)\\s*Authorization\\s*:\\s*Bearer\\s+' + escapeRegex(expectedToken) + '\\s*($|,|\\n)', 'i');
    if (authRegex.test(headersRaw)) {
        try {
            var payload = JSON.parse(bodyRaw);
            if (payload && typeof payload.content === 'string' && payload.content.length > 0) {
                tailclip_content = payload.content;
                tailclip_status = '200';
            } else {
                tailclip_status = '400';
            }
        } catch (e) {
            tailclip_status = '400';
        }
    }
}
